css:
/* --- Hero --- */
.hero_box {
  background: linear-gradient(135deg, #fff7ed 0%, #fef3c7 50%, #ecfdf5 100%);
  padding: 60px 40px 60px;
  text-align: center;
  border-radius: 0 0 16px 16px;
  margin-bottom: 40px;
}
.hero-mikan {
  margin: 0;
  font-size: 3rem;
  animation: bounce 1.8s ease-in-out infinite;
}
@keyframes bounce {
  0%, 100% {
    transform: translateY(0);
  }
  50% {
    transform: translateY(-12px);
  }
}
.hero-badge {
  display: inline-block;
  background: #f97316;
  color: #fff;
  font-size: 0.85rem;
  font-weight: 700;
  padding: 4px 14px;
  border-radius: 50px;
  margin-bottom: 20px;
  letter-spacing: 0.06em;
}
h1 {
  font-size: clamp(1.8rem, 5vw, 3rem);
  font-weight: 800;
  line-height: 1.3;
  color: #1e293b;
  margin-bottom: 16px;
  margin-top: 0;
}
.hero-subtitle {
  font-size: 1.05rem;
  color: #475569;
  max-width: 480px;
  margin: 0 auto;
  line-height: 1.6;
}
